import re

with open('./llvm/lib/Transforms/Scalar/EarlyCSE.cpp', 'r') as f:
    content = f.read()

# Fix 1: Update CmpInst hash function to handle samesign
cmp_hash_pattern = r'if \(CmpInst \*CI = dyn_cast<CmpInst>\(Inst\)\) \{\n(.*?\n)*?    return hash_combine\(Inst->getOpcode\(\), Pred, LHS, RHS\);\n  \}'
cmp_hash_replacement = '''  if (CmpInst *CI = dyn_cast<CmpInst>(Inst)) {
    // Compares can be commuted by swapping the comparands and
    // updating the predicate.  Choose the form that has the
    // comparands in sorted order, or in the case of a tie, the
    // one with the lower predicate.
    Value *LHS = CI->getOperand(0);
    Value *RHS = CI->getOperand(1);
    // For ICmpInst, we need to include samesign information in the hash
    if (auto *ICI = dyn_cast<ICmpInst>(CI)) {
      CmpPredicate Pred = ICI->getCmpPredicate();
      CmpPredicate SwappedPred = ICI->getSwappedCmpPredicate();
      if (std::make_tuple(LHS, CmpInst::Predicate(Pred), Pred.hasSameSign()) >
          std::make_tuple(RHS, CmpInst::Predicate(SwappedPred), SwappedPred.hasSameSign())) {
        std::swap(LHS, RHS);
        Pred = SwappedPred;
      }
      return hash_combine(Inst->getOpcode(), Pred, LHS, RHS);
    } else {
      // FCmpInst doesn't have samesign
      CmpInst::Predicate Pred = CI->getPredicate();
      CmpInst::Predicate SwappedPred = CI->getSwappedPredicate();
      if (std::tie(LHS, Pred) > std::tie(RHS, SwappedPred)) {
        std::swap(LHS, RHS);
        Pred = SwappedPred;
      }
      return hash_combine(Inst->getOpcode(), Pred, LHS, RHS);
    }
  }'''

# Use regex to find and replace
content = re.sub(cmp_hash_pattern, cmp_hash_replacement, content, flags=re.DOTALL)

# Fix 2: Update select hash function to use getInverseCmpPredicate
select_hash_pattern = r'if \(CmpInst::getInversePredicate\(Pred\) < Pred\) \{\n      Pred = CmpInst::getInversePredicate\(Pred\);\n      std::swap\(A, B\);\n    \}'
select_hash_replacement = '''    if (CmpInst::Predicate(CmpPredicate::getInverseCmpPredicate(Pred)) < CmpInst::Predicate(Pred)) {
      Pred = CmpPredicate::getInverseCmpPredicate(Pred);
      std::swap(A, B);
    }'''
content = re.sub(select_hash_pattern, select_hash_replacement, content)

# Fix 3: Update CmpInst equality function to handle samesign
cmp_eq_pattern = r'return LHSCmp->getOperand\(0\) == RHSCmp->getOperand\(1\) &&\n           LHSCmp->getOperand\(1\) == RHSCmp->getOperand\(0\) &&\n           LHSCmp->getSwappedPredicate\(\) == RHSCmp->getPredicate\(\);'
