               LHSCmp->getOperand(1) == RHSCmp->getOperand(0) &&
               CmpPredicate::getMatching(LHSICI->getCmpPredicate(),
                                         RHSICI->getSwappedCmpPredicate()).has_value();
      }
    }
    // For FCmpInst or mixed types, use the old logic (no samesign)
    return LHSCmp->getOperand(0) == RHSCmp->getOperand(1) &&
           LHSCmp->getOperand(1) == RHSCmp->getOperand(0) &&
           LHSCmp->getSwappedPredicate() == RHSCmp->getPredicate();'''
content = re.sub(cmp_eq_pattern, cmp_eq_replacement, content)

with open('./llvm/lib/Transforms/Scalar/EarlyCSE.cpp', 'w') as f:
    f.write(content)
EOF
